/* Token values cannot be used inside @media min-width directly -
   reference the documented px values. */

@media (min-width: 768px) { /* md */ }
@media (min-width: 1024px) { /* lg */ }

import hds from '@/design-system/tokens';

// Named values - no magic numbers
const isMobile = window.innerWidth < hds.breakpoints.md;  // < 768

// In a resize handler
const cols = window.innerWidth >= hds.breakpoints.lg ? 3
           : window.innerWidth >= hds.breakpoints.md ? 2
           : 1;
